import CloseIcon from "@mui/icons-material/Close";
import EventIcon from '@mui/icons-material/Event';
import SaveIcon from "@mui/icons-material/Save";
import {
    Box,
    Button, Grid, IconButton, InputAdornment, MenuItem, Select, TextField, Typography
} from "@mui/material";
import { MobileDatePicker } from "@mui/x-date-pickers";
import { AdapterDateFns } from '@mui/x-date-pickers/AdapterDateFns';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import { default as React, useEffect, useState } from 'react';

const formStyle = {
    position: 'absolute',
    top: '50%',
    left: '50%',
    transform: 'translate(-50%, -50%)',
    width: 330,
    bgcolor: 'background.paper',
    border: '2px solid #284871',
    boxShadow: 24,
    p: 2,
    maxHeight: '300px', 
    overflow: 'auto'
};

const ModificationForm = (props) => {

    const [formValues, setFormValues] = useState(props.event)
    const [dateEMValue, setEMDateValue] = useState(null);
    const [dateOCValue, setOCDateValue] = useState(null);

    const [isEMOpen, setIsEMOpen] = useState(false);
    const [isOCOpen, setIsOCOpen] = useState(false);

    useEffect(() => {
        
        setFormValues(props.event);
        if (props.event.startingDateEEMM != null) {
            setEMDateValue(props.event.startingDateEEMM);
        }

        if (props.event.startingDateOOCC != null) {
            setOCDateValue(props.event.startingDateOOCC);
        }
    }, [props.event]);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormValues({
            ...formValues,
            [name]: value,
        });
    };

    const handleSubmit = () => {

        formValues.startingDateEEMM = dateEMValue;
        formValues.startingDateOOCC = dateOCValue;
        console.log(formValues);
        props.onUpdatedWindfarm(formValues);
        setEMDateValue(null);
        setOCDateValue(null);
    }

    return (
        <Box sx={formStyle} >
            <Typography align="center" id="modal-modal-title" variant="h6" >
                MODIFICA INTERVENTO
            </Typography>
            <Box pt={3} />
            <Grid container direction="column" alignItems="center" rowSpacing={2}>

                <Grid item >
                    <TextField style={{ width: 180, height: 50 }}
                        required
                        disabled
                        error={formValues.turbineName === ""}
                        id="turbine-input"
                        name="turbineName"
                        label="Aerogeneratore"
                        type="text"
                        value={formValues.turbineName}
                        onChange={handleInputChange}
                    />
                    <TextField style={{ width: 70, height: 50}}
                        id="turbine-number"
                        name="turbineNumber"
                        type="text"
                        value={formValues.turbineNumber}
                        onChange={handleInputChange}
                    />
                </Grid>
                <Grid item >
                    <TextField style={{ width: 250, height: 50 }}
                        required
                        error={formValues.description === ""}
                        id="description-input"
                        name="description"
                        label="Impianto Eolico"
                        type="text"
                        value={formValues.description}
                        onChange={handleInputChange}
                    />
                </Grid>
                <Grid item >
                    <TextField style={{ width: 250, height: 50 }}
                        id="odl-number-mod"
                        name="odlNumber"
                        label="Numero ODL"
                        type="text"
                        value={formValues.odlNumber}
                        onChange={handleInputChange}
                    />
                </Grid>
                <Grid item >
                    <Select style={{ width: 250, height: 50 }}
                        name="operation" value={formValues.operation} onChange={handleInputChange} multiple 
                        error={formValues.operation.length === 0} required >
                        <MenuItem key="1" value="Sostituzione Traversa">Sost. Traversa</MenuItem>
                        <MenuItem key="2" value="Riparazione pale">Riparazione pale</MenuItem>
                        <MenuItem key="3" value="Sostituzione trafo">Sost. trafo</MenuItem>
                        <MenuItem key="4" value="Sostituzione generatore">Sost. generatore</MenuItem>
                        <MenuItem key="5" value="Sostituzione Ralla">Sost. Ralla</MenuItem>
                        <MenuItem key="6" value="Pulizia Tubolare">Pulizia tubolare</MenuItem>
                        <MenuItem key="7" value="Sostituzione IMS">Sost. IMS</MenuItem>
                        <MenuItem key="8" value="Serraggio bulloni nose cone">Serraggio Nose Cone</MenuItem>
                        <MenuItem key="9" value="Sostituzione Stella HUB">Sost. Stella HUB</MenuItem>
                        <MenuItem key="10" value="Sostituzione Pala discesa rotore">Sost. Pala discesa rotore</MenuItem>
                        <MenuItem key="11" value="Sostituzione cuscinetto">Sost. cuscinetto</MenuItem>
                        <MenuItem key="12" value="Sostituzione Asta Pitch">Sost. Asta Pitch</MenuItem>
                        <MenuItem key="13" value="Sostituzione Yaw Gear">Sost. Yaw Gear</MenuItem>
                        <MenuItem key="14" value="Sostituzione Gearbox">Sost. Gearbox</MenuItem>
                        <MenuItem key="15" value="Sostituzione Pala RJ">Sost. Pala RJ</MenuItem>
                        <MenuItem key="16" value="Sostituzione Albero lento">Sost. Albero lento</MenuItem>
                        <MenuItem key="17" value="Ispezione RJ">Ispezione RJ</MenuItem>
                        <MenuItem key="18" value="Manutenzione ordinaria viabilità">Manutenzione ordinaria viabilità</MenuItem>
                    </Select>
                </Grid>
                <Grid item >
                    <Select style={{ width: 250, height: 50 }}
                        name="turbineState" value={formValues.turbineState} onChange={handleInputChange}>
                        <MenuItem key="1" value="In marcia">In marcia</MenuItem>
                        <MenuItem key="2" value="Ferma">Ferma</MenuItem>
                        <MenuItem key="3" value="Limitata">Limitata</MenuItem>
                    </Select>
                </Grid>
                <Grid item >
                    <Select style={{ width: 250, height: 50 }}
                        name="power" value={formValues.power} onChange={handleInputChange}>
                        <MenuItem key="1" value="MEGAWATT">Megawatt</MenuItem>
                        <MenuItem key="2" value="KILOWATT">Kilowatt</MenuItem>
                    </Select>
                </Grid>
                <Grid item >
                    <LocalizationProvider dateAdapter={AdapterDateFns} >
                        <MobileDatePicker
                            label="Avvio attività OOCC"
                            value={dateOCValue}
                            open={isOCOpen}
                            onOpen={() => { setIsOCOpen(true) }}
                            onClose={() => { setIsOCOpen(false) }}
                            onChange={setOCDateValue}
                            renderInput={(params) => (
                                <TextField
                                    {...params}
                                    InputProps={{
                                        endAdornment: (
                                            <InputAdornment position="end">
                                                <IconButton edge="end" onClick={() => { setIsOCOpen(true) }}>
                                                    <EventIcon />
                                                </IconButton>
                                            </InputAdornment>
                                        ),
                                    }}
                                />
                            )}
                        />
                    </LocalizationProvider>
                </Grid>
                <Grid item >
                    <LocalizationProvider dateAdapter={AdapterDateFns} >
                        <MobileDatePicker
                            label="Avvio attività EEMM"
                            value={dateEMValue}
                            open={isEMOpen}
                            onOpen={() => { setIsEMOpen(true) }}
                            onClose={() => { setIsEMOpen(false) }}
                            onChange={setEMDateValue}
                            renderInput={(params) => (
                                <TextField
                                    {...params}
                                    InputProps={{
                                        endAdornment: (
                                            <InputAdornment position="end">
                                                <IconButton edge="end" onClick={() => { setIsEMOpen(true) }}>
                                                    <EventIcon />
                                                </IconButton>
                                            </InputAdornment>
                                        ),
                                    }}
                                />
                            )}
                        />
                    </LocalizationProvider>
                </Grid>
                <Grid container direction="row" justifyContent="center" alignItems="center"  >
                    <Grid item m={4} xs={2}>
                        <Button
                            variant="contained"
                            startIcon={<CloseIcon />}
                            onClick={props.onClose}>
                            CHIUDI
                        </Button>
                    </Grid>
                    <Grid item xs={4} m={4}>
                        <Button
                            disabled={formValues.name === "" || formValues.description === "" || formValues.operation.length === 0}
                            variant="contained"
                            startIcon={<SaveIcon />}
                            onClick={handleSubmit}
                        >
                            MODIFICA
                        </Button>
                    </Grid>
                </Grid>
            </Grid>
        </Box >
    );
}

export default ModificationForm;
